var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"사흘 뒤","JPN":"4日後","ENG":"Four days later","TWN":"三天後","THA":"สี่วันต่อมา","VTN":"Bốn ngày sau","SCN":"三天后","DEU":"Drei Tage später","FRA":"4 jours plus tard"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드 상업지구, 중앙 병원 응급진료실","JPN":"シャレード商業地区、中央病院救急室","ENG":"Charade Commercial District, Central Hospital Emergency Clinic","TWN":"查雷德商業區，中央醫院急診室","THA":"ย่านการค้าชาเรด คลินิกฉุกเฉินโรงพยาบาลกลาง","VTN":"Khu thương mại Charade, Phòng Cấp Cứu Bệnh Viện Trung Ương","SCN":"查雷德商业区，中央医院急诊室","DEU":"Charades Geschäftsviertel, Notaufnahme des Zentralkrankenhauses","FRA":"Quartier des affaires de Charade, salle d'urgence de l'hôpital central"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서 라이카 양의 몸 상태는 좀 어떤가?","JPN":"それで、ライカ君の身体の具合はどうかね？","ENG":"So, how's Laika's condition?","TWN":"萊卡的身體狀況如何？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"의사 말로는 행운이라네요. 상처가 조금만 비껴 나갔어도 그 자리에서 죽었을 거라고.","JPN":"医者には運がよかったと言われました。傷が少しでもずれていたら、その場で死んでいたはずだって。","ENG":"The doctor says she was lucky. If her wound had been more to the side, she would've died on the spot.","TWN":"醫生說算她命大，傷口只要再傾斜一點，她就會當場死亡。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"수술은 잘 끝났다는데…… 어깨는 당분간 경과를 지켜봐야 하나봐요.","JPN":"手術は成功に終わったらしいですけど……肩はしばらく様子を見ないといけないみたいです。","ENG":"Her surgery went well, but... they'll have to monitor her shoulder for a while longer.","TWN":"手術已經順利結束……肩膀需要觀察一段時間。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼, 되도록 어깨를 쓰지 않는 편이 좋겠군.","JPN":"それでは、なるべく肩は使わない方がいいだろうな。","ENG":"Then, it would be better for her not to use her shoulder.","TWN":"那還是盡量不要使用到肩膀吧。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"역시 스폰서가 있어야 한다니까. 원래는 진통제나 몇 알 받고 쫓겨났을 텐데.","JPN":"やっぱりスポンサーがいるっていいよな。本来なら鎮痛剤なんかをちょびっともらって、追い出されてたはずだろ。","ENG":"This is why we need sponsors. Normally, they would've just given me painkillers and kicked me out.","TWN":"贊助商真的很重要欸，竟然沒有用幾顆止痛藥就打發我。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"너무 걱정마셔, 이 정도 부상은 아무것도 아니니까.","JPN":"心配するなよ、この程度の怪我は何でもないし。","ENG":"But don't worry too much. It's not a big injury or anything.","TWN":"放心啦，這點小傷不算什麼。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"다음 경기까진…… ","JPN":"次の試合までは…… ","ENG":"I'll be ready for the next match–","TWN":"在下一場比賽之前…… "},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"앗, 아아아!","JPN":"あっ、あああ！","ENG":"Ow, owowow!","TWN":"啊啊啊啊！"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"너 방금 뭐 듣고 있었니? 아직 어깨 움직이면 안 된다니까?","JPN":"今までの話聞いてた？　まだ肩を動かしちゃダメだってば。","ENG":"Weren't you listening? You're not supposed to move your shoulder!","TWN":"你剛沒在聽嗎？不是叫你盡量不要用到肩膀？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"당분간은 안정을 취하는 편이 좋겠네.","JPN":"しばらくは安静にした方が良さそうだな。","ENG":"It's absolute bed rest for you for the time being.","TWN":"你暫時先好好休養吧。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"아무래도 대체 선수가 필요할 것 같은데.","JPN":"どうやら、代わりの選手が必要になりそうだ。","ENG":"I believe we will need a substitute.","TWN":"看來可能需要找人代替你出賽。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……거 참. 미안하게 됐어, 코치.","JPN":"……まったく。悪いな、コーチ。","ENG":"...Ugh. Sorry about this, Coach.","TWN":"……真抱歉，造成大家困擾。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니, 사과할 필요는 없네.","JPN":"いいや、謝る必要はない。","ENG":"No, there's no need to apologize.","TWN":"別這麼說，你不需要道歉。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};